//* DEFINE TRANSACATION TYPE VSAM FILE                                          
//* *******************************************************************

//STEP30   EXEC PGM=IEFBR14,COND=(0,NE)
//DD01     DD DISP=(MOD,DELETE,DELETE),
//            UNIT=SYSDA,
//            SPACE=(TRK,(1,1)),
//            DSN=&HLQ..TRANTYPE.PS
//DD02     DD DISP=(MOD,DELETE,DELETE),
//            UNIT=SYSDA,
//            SPACE=(TRK,(1,1)),
//            DSN=&HLQ..TRANCATG.PS
//*********************************************************************
//****  STEP 40 : EXTRACT DATA FROM TRANSACTION TYPE TABLE       ******
//*********************************************************************

//STEP15 EXEC PGM=IDCAMS                                                        
//SYSPRINT DD   SYSOUT=*                                                        
//TRANTYPE DD DISP=SHR,                                                         
//         DSN=AWS.M2.CARDDEMO.TRANTYPE.PS                                      
//TTYPVSAM DD DISP=OLD,                                                         
//         DSN=AWS.M2.CARDDEMO.TRANTYPE.VSAM.KSDS                               
//SYSIN    DD   *                                                               
   REPRO INFILE(TRANTYPE) OUTFILE(TTYPVSAM)                                     
/*                                                                              
//*
//* Ver: CardDemo_v1.0-15-g27d6c6f-68 Date: 2022-07-19 23:23:08 CDT
//*

//STEP10 EXEC PGM=IDCAMS                                                        
//SYSPRINT DD   SYSOUT=*                                                        
//SYSIN    DD   *                                                               
   DEFINE CLUSTER (NAME(AWS.M2.CARDDEMO.TRANTYPE.VSAM.KSDS) -                   
          CYLINDERS(1 5) -                                                      
          VOLUMES(AWSHJ1 -                                                      
          ) -                                                                   
          KEYS(2 0) -                                                           
          RECORDSIZE(60 60) -                                                   
          SHAREOPTIONS(1 4) -                                                   
          ERASE -                                                               
          INDEXED -                                                             
          ) -                                                                   
          DATA (NAME(AWS.M2.CARDDEMO.TRANTYPE.VSAM.KSDS.DATA) -                 
          ) -                                                                   
          INDEX (NAME(AWS.M2.CARDDEMO.TRANTYPE.VSAM.KSDS.INDEX) -               
          )                                                                     
/*                                                                              
//* *******************************************************************         
//* COPY DATA FROM FLAT FILE TO VSAM FILE                                       
//* *******************************************************************

//STEP40   EXEC PGM=IKJEFT01,COND=(0,NE)
//STEPLIB  DD  DISP=SHR,DSN=OEM.DB2.DAZ1.RUNLIB.LOAD
//         DD  DISP=SHR,DSN=OEMA.DB2.VERSIONA.SDSNLOAD
//SYSTSPRT DD  SYSOUT=*
//SYSPRINT DD  SYSOUT=*
//SYSUDUMP DD  SYSOUT=*
//SYSPUNCH DD  DUMMY
//SYSREC00 DD  DISP=(NEW,CATLG,DELETE),
//             DSN=&HLQ..TRANTYPE.PS,
//             SPACE=(TRK,(1,1),RLSE)
//SYSIN    DD *
 SELECT CAST(CONCAT(CONCAT(
   TR_TYPE
  ,CAST(TR_DESCRIPTION AS CHAR(50))
   )
  ,REPEAT('0',8)
 ) AS CHAR(60))
  FROM
  CARDDEMO.TRANSACTION_TYPE
  ORDER BY TR_TYPE;
